import { 運筆 } from '../bi.js';
// 頸瓔：一弧綴珠，貼頸
export function 頸瓔(bi) {
    const { M, Qk, S, 細 } = 運筆(bi);
    細(() => {
        M(-2.9, 25.3);
        Qk(0, 26.3, 2.9, 25.3);
        S();
        for (const [bx, bz] of [[-2.0, 25.7], [-0.85, 26.0], [0.85, 26.0], [2.0, 25.7]])
            bi.dot(bx, bz, 0.22);
    });
}
// 胸瓔：垂弧至胸，綴珠，中懸一滴（滴z＝滴珠中心，可參以讓開胸前結印之地）
export function 胸瓔(bi, 參 = {}) {
    const { 滴z = 30.7 } = 參;
    const { M, C, S, 細 } = 運筆(bi);
    細(() => {
        M(-3.7, 25.9);
        C(-4.4, 27.4, -3.0, 29.4, 0, 30.1);
        C(3.0, 29.4, 4.4, 27.4, 3.7, 25.9);
        S();
        for (const [bx, bz] of [[-3.6, 27.3], [-2.3, 28.9], [2.3, 28.9], [3.6, 27.3]])
            bi.dot(bx, bz, 0.24);
        bi.dot(0, 滴z, 0.28);
    });
}
// 臂釧：雙環繞臂，環間一珠——一側之釧；d＝±1，x0 內緣、x1 外緣、z 上環之高
export function 臂釧(bi, d, x0 = 12.0, x1 = 14.3, z = 33.6) {
    const { M, Qk, S, 細 } = 運筆(bi);
    const xm = (x0 + x1) / 2;
    細(() => {
        M(d * x0, z);
        Qk(d * xm, z + 0.5, d * x1, z - 0.1);
        S();
        M(d * (x0 + 0.05), z + 1.1);
        Qk(d * xm, z + 1.6, d * (x1 + 0.05), z + 1.0);
        S();
        bi.dot(d * xm, z + 1.05, 0.2);
    });
}
// 腕釧：雙環過腕，環間一珠——環各以 [x0,z0,cx,cz,x1,z1] 二次曲線與臂勢相順
export function 腕釧(bi, 環, 珠) {
    const { M, Qk, S, 細 } = 運筆(bi);
    細(() => {
        for (const [x0, z0, cx, cz, x1, z1] of 環) {
            M(x0, z0);
            Qk(cx, cz, x1, z1);
            S();
        }
        bi.dot(珠[0], 珠[1], 0.18);
    });
}
